import sys
import math


def gcd(a, b):
    if a == 0:
        return b
    return gcd(b % a, a)


def lcm(a, b):
    return a * b // gcd(a, b)


m = int(input())

gcd_list = [0] * (m + 1)

for i in range(1, m + 1):
    gcd_list[i] = gcd(i, gcd_list[i - 1])


def gcd_sum(n):
    if n <= 0:
        return 0
    return n + gcd_sum(n - 1)


def solve(m):
    result = 0
    for i in range(1, m + 1):
        result += gcd_sum(i) * gcd_list[i]
    return result


result = solve(m)

print(result)
